const DISCOUNT_RULES = {
  premium: [
    { minAmount: 100, discount: 0.20 },
    { minAmount: 50,  discount: 0.15 },
    { minAmount: 0,   discount: 0.10 },
  ],
  regular: [
    { minAmount: 100, discount: 0.10 },
    { minAmount: 50,  discount: 0.05 },
    { minAmount: 0,   discount: 0.00 },
  ],
  new: [
    { minAmount: 0,   discount: 0.05 },
  ],
};

function getDiscount(userType, purchaseAmount) {
  const rules = DISCOUNT_RULES[userType];
  if (!rules) return 0;

  const rule = rules.find(r => purchaseAmount >= r.minAmount);
  return rule?.discount ?? 0;
}
```

**Improvements:** Data-driven (add tiers by editing the table, not code). Single responsibility (logic is just a lookup). Open for extension (add user types without touching the function). Rules are sorted high-to-low, so `find` returns the first matching tier.

