class AppError extends Error {
  constructor(message, statusCode, isOperational = true) {
    super(message);
    this.statusCode = statusCode;
    this.isOperational = isOperational;
    Error.captureStackTrace(this, this.constructor);
  }
}

// Wrap async route handlers to catch rejected promises
const asyncHandler = (fn) => (req, res, next) => {
  Promise.resolve(fn(req, res, next)).catch(next);
};

// Error handling middleware (must have 4 params)
function errorHandler(err, req, res, next) {
  // Default values
  err.statusCode = err.statusCode || 500;
  err.isOperational = err.isOperational ?? false;

  // Log all errors
  const logPayload = {
    timestamp: new Date().toISOString(),
    method: req.method,
    path: req.path,
    statusCode: err.statusCode,
    message: err.message,
    stack: err.stack,
    requestId: req.headers['x-request-id'],
  };

  if (err.statusCode >= 500) {
    console.error('[ERROR]', JSON.stringify(logPayload));
  } else {
    console.warn('[WARN]', JSON.stringify(logPayload));
  }

  // Response based on environment
  const response = {
    status: 'error',
    statusCode: err.statusCode,
    message: err.isOperational
      ? err.message
      : process.env.NODE_ENV === 'production'
        ? 'Internal server error'
        : err.message,
  };

  // Include stack in development
  if (process.env.NODE_ENV !== 'production') {
    response.stack = err.stack;
  }

  res.status(err.statusCode).json(response);
}

// Handle known error types
function normalizeError(err) {
  if (err.name === 'ValidationError') {
    return new AppError(err.message, 400);
  }
  if (err.name === 'JsonWebTokenError') {
    return new AppError('Invalid token', 401);
  }
  if (err.code === '23505') { // Postgres unique violation
    return new AppError('Resource already exists', 409);
  }
  return err;
}

module.exports = { AppError, asyncHandler, errorHandler, normalizeError };
